{"code":"def parse_exchange_file(path, default_compartment):
    # Determine the file format
    fmt = resolve_format(None, path)
    if fmt is None:
        raise ParseError("Unsupported file format")

    with open(path, 'r') as f:
        if fmt == 'tsv':
            return parse_exchange_table_file(f)
        elif fmt == 'yaml':
            return parse_exchange_yaml_file(FilePathContext(path), f, default_compartment)
    raise ParseError("Could not determine file format")
